#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 10 (Layer 5): sintesis exploratoria OOC.
#
# Primera pasada de sintesis. Objetivo UNICO: averiguar donde acabaron las
# memorias tras la reestructuracion del Paso 9. Sin AXI ni NoC todavia.
#
# NO EJECUTADO POR CLAUDE: no hay Vivado en el contenedor de construccion.
# La sintaxis Tcl se valido con stubs (tclsh 8.6), incluyendo el camino de
# fallo, pero los comandos de Vivado NO se han probado.
#
# Instala en syn/ y se lanza con:
#   cd ~/vhdl_repo/IP_Cores/NPU
#   bash syn/run_synth.sh
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/rtl/npu_top.vhd" ]; then
  echo "FALLO: falta rtl/npu_top.vhd (corre primero los Pasos 1-9)"; exit 1
fi
mkdir -p "$DIR/syn"
base64 -d << "EOF" > "$DIR/syn/npu_synth_ooc.tcl"

EOF
base64 -d << "EOF" > "$DIR/syn/run_synth.sh"

EOF
chmod +x "$DIR/syn/run_synth.sh"
echo "Scripts de sintesis instalados en $DIR/syn/"
echo ""
echo "Para lanzar (necesita el entorno de Vivado cargado):"
echo "  cd $DIR"
echo "  bash syn/run_synth.sh"
)
